selector_to_html = {"a[href=\"#managing-requirements-with-pip-tools\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\">Managing Requirements with pip-tools<a class=\"headerlink\" href=\"#managing-requirements-with-pip-tools\" title=\"Link to this heading\">\u00b6</a></h1><h2>The golden rule<a class=\"headerlink\" href=\"#the-golden-rule\" title=\"Link to this heading\">\u00b6</a></h2><p>The compiled files are regenerated by the workflow (and locally via <code class=\"docutils literal notranslate\"><span class=\"pre\">pip-compile</span></code>). Any manual changes will be overwritten.</p>", "a[href=\"#upgrading-a-specific-package\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Upgrading a specific package<a class=\"headerlink\" href=\"#upgrading-a-specific-package\" title=\"Link to this heading\">\u00b6</a></h2><p>Then recompile downstream files as needed</p>", "a[href=\"#the-golden-rule\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">The golden rule<a class=\"headerlink\" href=\"#the-golden-rule\" title=\"Link to this heading\">\u00b6</a></h2><p>The compiled files are regenerated by the workflow (and locally via <code class=\"docutils literal notranslate\"><span class=\"pre\">pip-compile</span></code>). Any manual changes will be overwritten.</p>", "a[href=\"#adding-a-new-direct-dependency\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Adding a new direct dependency<a class=\"headerlink\" href=\"#adding-a-new-direct-dependency\" title=\"Link to this heading\">\u00b6</a></h2><p>Find the right <code class=\"docutils literal notranslate\"><span class=\"pre\">.in</span></code> file for where the dependency belongs:</p>", "a[href=\"#pinning-a-package-to-a-specific-version\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Pinning a package to a specific version<a class=\"headerlink\" href=\"#pinning-a-package-to-a-specific-version\" title=\"Link to this heading\">\u00b6</a></h2><p>Add a constraint in the <code class=\"docutils literal notranslate\"><span class=\"pre\">.in</span></code> file:</p>", "a[href=\"#upgrading-all-packages-at-once\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Upgrading all packages at once<a class=\"headerlink\" href=\"#upgrading-all-packages-at-once\" title=\"Link to this heading\">\u00b6</a></h2><p>This is what the automated workflow does every Monday. To do it locally:</p>", "a[href=\"#compile-order-reference\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Compile order reference<a class=\"headerlink\" href=\"#compile-order-reference\" title=\"Link to this heading\">\u00b6</a></h2><p>Always compile in this order when changes affect multiple levels:</p>", "a[href=\"#what-the-automated-workflow-does-vs-what-you-do-manually\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">What the automated workflow does vs what you do manually<a class=\"headerlink\" href=\"#what-the-automated-workflow-does-vs-what-you-do-manually\" title=\"Link to this heading\">\u00b6</a></h2>", "a[href=\"#removing-a-dependency\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Removing a dependency<a class=\"headerlink\" href=\"#removing-a-dependency\" title=\"Link to this heading\">\u00b6</a></h2><p>Remove it from the relevant <code class=\"docutils literal notranslate\"><span class=\"pre\">.in</span></code> file, then recompile the same way as adding. pip-compile will drop it (and any indirect deps that are no longer needed) from the compiled output automatically.</p>", "a[href=\"#deptry-false-positives\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">deptry false positives<a class=\"headerlink\" href=\"#deptry-false-positives\" title=\"Link to this heading\">\u00b6</a></h2><p>If deptry flags a package as unused but you know it\u2019s used (e.g. a CLI tool, a pytest plugin, or a package imported via a string), add it to <code class=\"docutils literal notranslate\"><span class=\"pre\">pyproject.toml</span></code>:</p>"}
skip_classes = ["headerlink", "sd-stretched-link"]

window.onload = function () {
    for (const [select, tip_html] of Object.entries(selector_to_html)) {
        const links = document.querySelectorAll(` ${select}`);
        for (const link of links) {
            if (skip_classes.some(c => link.classList.contains(c))) {
                continue;
            }

            tippy(link, {
                content: tip_html,
                allowHTML: true,
                arrow: true,
                placement: 'auto-start', maxWidth: 500, interactive: false,

            });
        };
    };
    console.log("tippy tips loaded!");
};
